import { SHIFT_TYPE_LABELS, SHIFT_TYPE_NORMALISE, DAY_TYPE_NORMALISE } from "./constants";
import { ShiftType, DayType } from "@/types/enums";
import type { WorkScheduleResponse } from "./types";

export interface PublicHoliday {
  id?: string;
  date: string;
  name: string;
  description?: string;
}

/** Returns the human-readable label for a ShiftType (e.g. "Morning Shift"). */
export const getShiftTypeLabel = (shiftType: ShiftType): string =>
  SHIFT_TYPE_LABELS[shiftType] ?? shiftType;

/** Normalises freeform input (e.g. "morning-shift") to a canonical ShiftType, or null. */
export const normaliseShiftType = (value: string): ShiftType | null =>
  SHIFT_TYPE_NORMALISE[value.toLowerCase()] ?? null;

/** Normalises freeform input to a canonical DayType, or null. */
export const normaliseDayType = (value: string): DayType | null =>
  DAY_TYPE_NORMALISE[value.toLowerCase()] ?? null;

export function normaliseHolidays(res: unknown): PublicHoliday[] {
  let arr: any[] = [];
  if (Array.isArray(res)) arr = res;
  else if (res && typeof res === "object") {
    const o = res as Record<string, any>;
    if (Array.isArray(o.data)) arr = o.data;
    else if (Array.isArray(o.items)) arr = o.items;
    else if (Array.isArray(o.holidays)) arr = o.holidays;
  }
  return arr.map((h) => ({
    id: h.id,
    date: h.holidayOnDate,
    name: h.name,
    description: h.description ?? "",
  }));
}

export function getInitials(name: string): string {
  return name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
}

export function getMemberIdFromSchedule(schedule: WorkScheduleResponse): string {
  return schedule.userProfile?.id || schedule.userId || `schedule-${schedule.id}`;
}

export function getMemberNameFromSchedule(schedule: WorkScheduleResponse): string {
  return (
    schedule.userProfile?.firstName ||
    schedule.userProfile?.fullName ||
    schedule.userFullName ||
    "Unknown"
  );
}
