import React from "react";
import { CheckSquare, Square, Users, Check } from "lucide-react";
import type { TeamMember } from "../types";

interface MemberFiltersProps {
  teamMembers: TeamMember[];
  selectedMembers: string[];
  toggleAllMembers: (select: boolean) => void;
  handleMemberToggle: (id: string) => void;
}

export const MemberFilters: React.FC<MemberFiltersProps> = ({
  teamMembers,
  selectedMembers,
  toggleAllMembers,
  handleMemberToggle,
}) => {
  const [search, setSearch] = React.useState("");
  const allSelected = selectedMembers.length === teamMembers.length;
  const noneSelected = selectedMembers.length === 0;

  const filteredMembers = teamMembers.filter(m =>
    m.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="flex flex-col gap-4 w-full">
      <div className="flex flex-wrap items-center gap-3">
        <div className="relative group">
          <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground group-focus-within:text-primary transition-colors" />
          <input
            type="text"
            placeholder="Search team members..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9 pr-4 py-1.5 bg-muted/50 border border-border rounded-xl text-xs font-medium placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all w-64"
          />
        </div>

        <div className="flex items-center gap-1.5">
          <button
            onClick={() => toggleAllMembers(true)}
            className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg border text-[11px] font-black uppercase tracking-wider transition-all ${
              allSelected
                ? "bg-foreground text-background border-transparent"
                : "bg-card text-muted-foreground border-border hover:bg-muted"
            }`}
          >
            <CheckSquare className="w-3.5 h-3.5" />
            Select All
          </button>

          <button
            onClick={() => toggleAllMembers(false)}
            className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg border text-[11px] font-black uppercase tracking-wider transition-all ${
              noneSelected
                ? "bg-foreground text-background border-transparent"
                : "bg-card text-muted-foreground border-border hover:bg-muted"
            }`}
          >
            <Square className="w-3.5 h-3.5" />
            Clear
          </button>
        </div>
      </div>

      <div className="flex flex-wrap items-center gap-2 max-h-32 overflow-y-auto pr-2 custom-scrollbar">
        {filteredMembers.map((m) => {
          const selected = selectedMembers.includes(m.id);
          return (
            <button
              key={m.id}
              onClick={() => handleMemberToggle(m.id)}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-medium transition-all border select-none ${
                selected
                  ? "shadow-sm"
                  : "bg-card text-muted-foreground border-border hover:border-border/80"
              }`}
              style={selected ? {
                backgroundColor: `${m.hexColor}15`,
                color: m.hexColor,
                borderColor: `${m.hexColor}40`
              } : {}}
            >
              <span
                className={`w-3.5 h-3.5 rounded-full flex items-center justify-center shrink-0 transition-all ${
                  selected ? "bg-current" : "border-2 border-border"
                }`}
                style={selected ? { opacity: 0.2 } : {}}
              >
                {selected && <Check className="w-2.5 h-2.5 text-white" />}
              </span>
              <span className="uppercase tracking-widest">{m.name}</span>
            </button>
          );
        })}

        {filteredMembers.length === 0 && (
          <span className="text-muted-foreground italic text-[11px] flex items-center gap-2 py-2">
            <Users className="w-3.5 h-3.5" /> No matching members found.
          </span>
        )}
      </div>
    </div>
  );
};
